import React, { useState, useEffect, useRef, useCallback } from "react";
import {
  Check, TrendingUp, RotateCcw, ChevronLeft, ChevronRight, Beaker, X, Plus,
  AlertTriangle, Trash2, Package, Sparkles, Settings, Apple, LayoutDashboard,
  MessageCircle, Star, Pencil, ChevronDown, ChevronUp, Clock, FlaskConical
} from "lucide-react";

const LOGO_SRC = "data:image/png;base64,";

// ── Constants ──────────────────────────────────────────────────────────────

const MACRO_PRESETS = {
  muscle:      { name: "Muscle Gain",  protein: 35, carbs: 45, fat: 20, icon: "💪" },
  fatLoss:     { name: "Fat Loss",     protein: 40, carbs: 30, fat: 30, icon: "🔥" },
  maintenance: { name: "Maintenance",  protein: 30, carbs: 40, fat: 30, icon: "⚖️" },
};

const RDA = { vitaminC: 90, vitaminD: 800, magnesium: 420, zinc: 11, iron: 8, calcium: 1000, potassium: 3500, sodium: 2300 };
const MICRO_LABELS = { vitaminC: "Vitamin C (mg)", vitaminD: "Vitamin D (IU)", magnesium: "Magnesium (mg)", zinc: "Zinc (mg)", iron: "Iron (mg)", calcium: "Calcium (mg)", potassium: "Potassium (mg)", sodium: "Sodium (mg)" };

const CATEGORY_DOT = { Daily: "bg-[#007AFF]", Peptide: "bg-purple-500", Support: "bg-amber-500", "GLP-1": "bg-emerald-500", Custom: "bg-pink-500" };
const CATEGORIES = ["Peptide", "Daily", "Support", "GLP-1", "Custom"];

const BRAND = "#007AFF";

// ── Utils ──────────────────────────────────────────────────────────────────

const getDateKey = d => `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
const formatDate = d => d.toLocaleDateString("en-US", { weekday: "long", month: "short", day: "numeric" });
const relativeDay = d => {
  const today = getDateKey(new Date());
  const yest  = getDateKey(new Date(Date.now()-86400000));
  const key   = getDateKey(d);
  if (key === today) return "Today";
  if (key === yest)  return "Yesterday";
  return d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" });
};
const calcUnits = (doseAmount, p) => p.bacMl > 0 && p.vialMg > 0 ? ((doseAmount / (p.vialMg / p.bacMl)) * 100).toFixed(1) : "—";
const dosesPerVial = p => p.doseAmount > 0 ? Math.floor(p.vialMg / p.doseAmount) : 0;
const entryCalories = e => Math.round((e.protein||0)*4 + (e.carbs||0)*4 + (e.fat||0)*9);
const dayTotals = entries => entries.reduce((a, e) => ({ protein: a.protein+(e.protein||0), carbs: a.carbs+(e.carbs||0), fat: a.fat+(e.fat||0), calories: a.calories+entryCalories(e) }), { protein:0, carbs:0, fat:0, calories:0 });

const emptyMicros = () => ({ vitaminC: null, vitaminD: null, magnesium: null, zinc: null, iron: null, calcium: null, potassium: null, sodium: null });
const microTotals = entries => entries.reduce((acc, e) => {
  if (!e.micros) return acc;
  Object.keys(RDA).forEach(k => { acc[k] = (acc[k]||0) + (e.micros[k]||0); });
  return acc;
}, {});

// ── PeptideEditor ──────────────────────────────────────────────────────────

function PeptideEditor({ peptide, onSave, onClose, onDelete, vialInfo }) {
  const isNew = !peptide.id;
  const [form, setForm] = useState({ name:"", category:"Peptide", vialMg:5, bacMl:2, unit:"mg", doseAmount:0.25, days:[1,3,5], ...peptide });

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const toggleDay = d => set("days", form.days.includes(d) ? form.days.filter(x=>x!==d) : [...form.days, d].sort());

  const doseLabel = `${form.doseAmount}${form.unit}`;
  const units = calcUnits(form.doseAmount, form);
  const total = dosesPerVial(form);

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/40 backdrop-blur-sm" onClick={onClose}>
      <div className="glass-card w-full max-w-md rounded-t-3xl rounded-b-none p-6 pb-10 space-y-4" onClick={e=>e.stopPropagation()}>
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-bold text-slate-900">{isNew ? "Add Compound" : "Edit Compound"}</h2>
          <button onClick={onClose} className="p-2 rounded-full bg-slate-100 text-slate-500"><X size={18}/></button>
        </div>

        <input className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white/80 text-slate-900 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" placeholder="Name (e.g. BPC-157)" value={form.name} onChange={e=>set("name",e.target.value)} />

        <div className="flex gap-2 flex-wrap">
          {CATEGORIES.map(c => (
            <button key={c} onClick={()=>set("category",c)} className={`px-3 py-1 rounded-full text-sm font-medium border transition-all ${form.category===c?"bg-[#007AFF] text-white border-[#007AFF]":"bg-white text-slate-600 border-slate-200"}`}>{c}</button>
          ))}
        </div>

        <div className="grid grid-cols-3 gap-2">
          <div>
            <label className="text-xs text-slate-500 mb-1 block">Vial Size</label>
            <input type="number" className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form.vialMg} onChange={e=>set("vialMg",parseFloat(e.target.value)||0)} />
          </div>
          <div>
            <label className="text-xs text-slate-500 mb-1 block">BAC Water (ml)</label>
            <input type="number" className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form.bacMl} onChange={e=>set("bacMl",parseFloat(e.target.value)||0)} />
          </div>
          <div>
            <label className="text-xs text-slate-500 mb-1 block">Unit</label>
            <select className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form.unit} onChange={e=>set("unit",e.target.value)}>
              <option>mg</option><option>IU</option>
            </select>
          </div>
        </div>

        <div>
          <label className="text-xs text-slate-500 mb-1 block">Dose per Injection ({form.unit})</label>
          <input type="number" step="0.05" className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form.doseAmount} onChange={e=>set("doseAmount",parseFloat(e.target.value)||0)} />
          {units !== "—" && <p className="text-xs text-slate-400 mt-1">{units} units on 100u syringe · {total} doses/vial</p>}
        </div>

        <div>
          <label className="text-xs text-slate-500 mb-2 block">Injection Days</label>
          <div className="flex gap-2">
            {["Su","Mo","Tu","We","Th","Fr","Sa"].map((d,i)=>(
              <button key={i} onClick={()=>toggleDay(i)} className={`flex-1 py-2 rounded-xl text-xs font-semibold border transition-all ${form.days.includes(i)?"bg-[#007AFF] text-white border-[#007AFF]":"bg-white text-slate-500 border-slate-200"}`}>{d}</button>
            ))}
          </div>
        </div>

        {vialInfo && (
          <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 text-sm text-amber-700">
            <span className="font-semibold">Vial:</span> {vialInfo.dosesUsed}/{total} doses used
            {vialInfo.expiryDate && <span className="ml-2">· Expires {vialInfo.expiryDate}</span>}
          </div>
        )}

        <div className="flex gap-3 pt-2">
          {!isNew && <button onClick={onDelete} className="flex-none px-4 py-3 rounded-xl bg-red-50 text-red-500 border border-red-200 font-medium text-sm"><Trash2 size={16}/></button>}
          <button onClick={()=>onSave({...form,doseLabel})} className="flex-1 py-3 rounded-xl font-semibold text-white text-sm" style={{background:BRAND}}>
            {isNew ? "Add to Stack" : "Save Changes"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── FoodModal ──────────────────────────────────────────────────────────────

function FoodModal({ initial, onSave, onClose, favourites, onFavourite }) {
  const isEdit = !!initial?.id;
  const [form, setForm] = useState({ note:"", micros: emptyMicros(), ...initial, protein: initial?.protein??"", carbs: initial?.carbs??"", fat: initial?.fat??"" });
  const [showMicros, setShowMicros] = useState(false);
  const [showFavs, setShowFavs] = useState(favourites.length > 0);

  const set = (k,v) => setForm(f=>({...f,[k]:v}));
  const setMicro = (k,v) => setForm(f=>({...f, micros:{...f.micros,[k]:v===""?null:parseFloat(v)||0}}));

  const loadFav = fav => setForm(f=>({...f, protein:fav.protein, carbs:fav.carbs, fat:fav.fat, note:fav.note||f.note, micros:fav.micros||emptyMicros()}));

  const cals = Math.round((parseFloat(form.protein)||0)*4 + (parseFloat(form.carbs)||0)*4 + (parseFloat(form.fat)||0)*9);

  const handleSave = () => {
    const entry = {
      id: initial?.id || `e_${Date.now()}`,
      protein: parseFloat(form.protein)||0,
      carbs: parseFloat(form.carbs)||0,
      fat: parseFloat(form.fat)||0,
      note: form.note,
      micros: form.micros,
      time: initial?.time || new Date().toLocaleTimeString("en-US",{hour:"numeric",minute:"2-digit"}),
    };
    onSave(entry);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/40 backdrop-blur-sm" onClick={onClose}>
      <div className="glass-card w-full max-w-md rounded-t-3xl rounded-b-none p-6 pb-10 space-y-4 max-h-[90vh] overflow-y-auto" onClick={e=>e.stopPropagation()}>
        <div className="flex items-center justify-between">
          <h2 className="text-lg font-bold text-slate-900">{isEdit ? "Edit Entry" : "Log Food"}</h2>
          <button onClick={onClose} className="p-2 rounded-full bg-slate-100 text-slate-500"><X size={18}/></button>
        </div>

        {!isEdit && favourites.length > 0 && (
          <div>
            <button className="flex items-center gap-1 text-xs font-semibold text-[#007AFF] mb-2" onClick={()=>setShowFavs(s=>!s)}>
              <Star size={12} fill={showFavs?"#007AFF":"none"}/> Favourites {showFavs ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
            </button>
            {showFavs && (
              <div className="flex flex-wrap gap-2">
                {favourites.map(fav=>(
                  <button key={fav.id} onClick={()=>loadFav(fav)} className="px-3 py-1.5 rounded-xl bg-[#007AFF]/10 text-[#007AFF] text-xs font-medium border border-[#007AFF]/20">
                    {fav.name}
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        <input className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white/80 text-slate-900 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" placeholder="Label (optional)" value={form.note} onChange={e=>set("note",e.target.value)} />

        <div className="grid grid-cols-3 gap-2">
          {[["protein","Protein (g)","#007AFF"],["carbs","Carbs (g)","#F59E0B"],["fat","Fat (g)","#8B5CF6"]].map(([k,label,color])=>(
            <div key={k}>
              <label className="text-xs font-semibold mb-1 block" style={{color}}>{label}</label>
              <input type="number" className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form[k]} onChange={e=>set(k,e.target.value)} placeholder="0" />
            </div>
          ))}
        </div>

        {cals > 0 && <p className="text-center text-sm font-semibold text-slate-600">{cals} kcal</p>}

        <button className="flex items-center gap-2 text-xs font-semibold text-slate-500" onClick={()=>setShowMicros(s=>!s)}>
          {showMicros ? <ChevronUp size={14}/> : <ChevronDown size={14}/>} Micronutrients (optional)
        </button>

        {showMicros && (
          <div className="grid grid-cols-2 gap-2">
            {Object.entries(MICRO_LABELS).map(([k,label])=>(
              <div key={k}>
                <label className="text-xs text-slate-400 mb-1 block">{label}</label>
                <input type="number" className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-900 text-sm focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={form.micros[k]??""} onChange={e=>setMicro(k,e.target.value)} placeholder="—" />
              </div>
            ))}
          </div>
        )}

        <div className="flex gap-3 pt-2">
          {isEdit && onFavourite && (
            <button onClick={()=>onFavourite(initial)} className="px-4 py-3 rounded-xl bg-amber-50 text-amber-500 border border-amber-200">
              <Star size={16}/>
            </button>
          )}
          <button onClick={handleSave} className="flex-1 py-3 rounded-xl font-semibold text-white text-sm" style={{background:BRAND}}>
            {isEdit ? "Save Changes" : "Log Entry"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── AssistantModal ─────────────────────────────────────────────────────────

function AssistantModal({ onClose, context }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:"smooth" }); }, [messages]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    const userMsg = { role:"user", content:text };
    const updated = [...messages, userMsg];
    setMessages(updated);
    setInput("");
    setLoading(true);
    try {
      const res = await fetch("/api/chat", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ messages: updated, context }),
      });
      const data = await res.json();
      if (data.content) setMessages(m => [...m, { role:"assistant", content:data.content }]);
      else setMessages(m => [...m, { role:"assistant", content:"Sorry, I couldn't get a response." }]);
    } catch {
      setMessages(m => [...m, { role:"assistant", content:"Network error. Check your connection." }]);
    }
    setLoading(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-[#F2F2F7]">
      <div className="glass-header px-4 py-4 flex items-center gap-3 safe-top">
        <button onClick={onClose} className="p-2 rounded-full bg-white/60 text-slate-600"><X size={20}/></button>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full flex items-center justify-center" style={{background:BRAND}}>
            <Sparkles size={16} className="text-white"/>
          </div>
          <div>
            <p className="font-bold text-slate-900 text-sm">RICO Assistant</p>
            <p className="text-xs text-slate-400">Powered by Claude</p>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3">
        {messages.length === 0 && (
          <div className="text-center pt-12">
            <div className="w-16 h-16 rounded-full mx-auto flex items-center justify-center mb-4" style={{background:BRAND+"22"}}>
              <MessageCircle size={28} style={{color:BRAND}}/>
            </div>
            <p className="text-slate-700 font-semibold mb-1">Ask me anything</p>
            <p className="text-slate-400 text-sm">I know your stack and today&apos;s nutrition.</p>
            <div className="mt-4 flex flex-wrap justify-center gap-2">
              {["What's in my stack?","How do I reconstitute BPC-157?","Review my macros"].map(q=>(
                <button key={q} onClick={()=>setInput(q)} className="px-3 py-1.5 rounded-full text-xs text-[#007AFF] bg-[#007AFF]/10 border border-[#007AFF]/20">{q}</button>
              ))}
            </div>
          </div>
        )}
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role==="user"?"justify-end":"justify-start"}`}>
            <div className={`max-w-[80%] px-4 py-3 rounded-2xl text-sm leading-relaxed ${m.role==="user"?"text-white":"glass-card text-slate-800"}`} style={m.role==="user"?{background:BRAND}:{}}>
              {m.content}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
            <div className="glass-card px-4 py-3 rounded-2xl">
              <div className="flex gap-1 items-center">
                <span className="w-2 h-2 rounded-full bg-slate-400 animate-bounce" style={{animationDelay:"0ms"}}/>
                <span className="w-2 h-2 rounded-full bg-slate-400 animate-bounce" style={{animationDelay:"150ms"}}/>
                <span className="w-2 h-2 rounded-full bg-slate-400 animate-bounce" style={{animationDelay:"300ms"}}/>
              </div>
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>

      <div className="glass-nav px-4 py-3 pb-safe flex gap-3 items-end">
        <textarea
          className="flex-1 px-4 py-3 rounded-2xl border border-slate-200 bg-white/80 text-slate-900 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-[#007AFF]"
          placeholder="Ask RICO..." rows={1} value={input}
          onChange={e=>setInput(e.target.value)}
          onKeyDown={e=>{ if(e.key==="Enter" && !e.shiftKey){ e.preventDefault(); send(); } }}
        />
        <button onClick={send} disabled={!input.trim()||loading} className="p-3 rounded-2xl text-white disabled:opacity-40 transition-opacity" style={{background:BRAND}}>
          <MessageCircle size={20}/>
        </button>
      </div>
    </div>
  );
}

// ── DashboardTab ───────────────────────────────────────────────────────────

function DashboardTab({ peptides, checked, nutritionData, stackStartDate, streak }) {
  const today = new Date();
  const days7 = Array.from({length:7},(_,i)=>{ const d=new Date(today); d.setDate(today.getDate()-6+i); return d; });

  const calorieTarget = nutritionData[getDateKey(today)]?.target || 2500;

  const barData = days7.map(d => {
    const key = getDateKey(d);
    const entries = nutritionData[key]?.entries || [];
    const target = nutritionData[key]?.target || calorieTarget;
    const cals = dayTotals(entries).calories;
    return { d, key, cals, target };
  });

  const maxCals = Math.max(...barData.map(b=>b.cals), calorieTarget, 100);

  const peptideArr = Object.values(peptides);
  const todayKey = getDateKey(today);
  const todayChecked = checked[todayKey] || {};
  const todayScheduled = peptideArr.filter(p=>p.days?.includes(today.getDay()));
  const todayDone = todayScheduled.filter(p=>todayChecked[p.id]).length;

  const week = stackStartDate ? Math.ceil((Date.now()-new Date(stackStartDate).getTime())/(7*86400000)) : null;

  const todayNutr = nutritionData[todayKey];
  const todayEntries = todayNutr?.entries || [];
  const totals = dayTotals(todayEntries);

  return (
    <div className="space-y-4 px-4 pb-4">
      {/* Quick stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="glass-card p-3 text-center">
          <p className="text-2xl font-bold text-slate-900">{streak}</p>
          <p className="text-xs text-slate-400 mt-0.5">Day streak</p>
        </div>
        <div className="glass-card p-3 text-center">
          <p className="text-2xl font-bold text-slate-900">{todayDone}/{todayScheduled.length}</p>
          <p className="text-xs text-slate-400 mt-0.5">Doses today</p>
        </div>
        <div className="glass-card p-3 text-center">
          <p className="text-2xl font-bold text-slate-900">{Math.round(totals.calories)}</p>
          <p className="text-xs text-slate-400 mt-0.5">kcal today</p>
        </div>
      </div>

      {/* Calorie bar graph */}
      <div className="glass-card p-4">
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide mb-4">7-Day Calorie Intake</p>
        <div className="flex items-end gap-2 h-28 relative">
          {/* target line */}
          <div className="absolute left-0 right-0 border-t-2 border-dashed border-slate-300" style={{bottom: `${(calorieTarget/maxCals)*100}%`}}/>
          {barData.map((b,i)=>{
            const heightPct = Math.max(4, (b.cals/maxCals)*100);
            const isOver = b.cals > b.target;
            const isToday = b.key === todayKey;
            return (
              <div key={i} className="flex-1 flex flex-col items-center gap-1">
                <div className="w-full rounded-t-lg transition-all" style={{height:`${heightPct}%`, background: b.cals===0?"#E5E7EB":isOver?"#EF4444":isToday?BRAND:"#34D399"}}/>
                <span className="text-[10px] text-slate-400">{b.d.toLocaleDateString("en-US",{weekday:"narrow"})}</span>
              </div>
            );
          })}
        </div>
        <div className="flex items-center gap-3 mt-3 text-xs text-slate-400">
          <span className="flex items-center gap-1"><span className="w-3 h-1.5 rounded bg-emerald-400 inline-block"/>Under</span>
          <span className="flex items-center gap-1"><span className="inline-block w-3 h-1.5 rounded" style={{background:BRAND}}/>Today</span>
          <span className="flex items-center gap-1"><span className="w-3 h-1.5 rounded bg-red-400 inline-block"/>Over</span>
          <span className="flex items-center gap-1"><span className="w-4 border-t-2 border-dashed border-slate-400 inline-block"/>Target</span>
        </div>
      </div>

      {/* Peptide adherence 7-day */}
      {peptideArr.length > 0 && (
        <div className="glass-card p-4">
          <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide mb-3">Peptide Adherence</p>
          <div className="flex gap-2">
            {days7.map(d => {
              const key = getDateKey(d);
              const scheduled = peptideArr.filter(p=>p.days?.includes(d.getDay()));
              const done = scheduled.filter(p=>(checked[key]||{})[p.id]).length;
              let color = "#E5E7EB";
              if (scheduled.length > 0) {
                if (done === scheduled.length) color = "#34D399";
                else if (done > 0) color = "#F59E0B";
                else color = "#EF4444";
              }
              const isToday = key === todayKey;
              return (
                <div key={key} className="flex-1 flex flex-col items-center gap-1">
                  <div className={`w-full aspect-square rounded-lg ${isToday?"ring-2 ring-offset-1":""}`} style={{background:color, ringColor:BRAND}}/>
                  <span className="text-[10px] text-slate-400">{d.toLocaleDateString("en-US",{weekday:"narrow"})}</span>
                </div>
              );
            })}
          </div>
          <div className="flex items-center gap-3 mt-3 text-xs text-slate-400">
            <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-emerald-400 inline-block"/>All done</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-amber-400 inline-block"/>Partial</span>
            <span className="flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-red-400 inline-block"/>Missed</span>
          </div>
        </div>
      )}

      {/* Stack info */}
      {week && (
        <div className="glass-card p-4 flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{background:BRAND+"22"}}>
            <Beaker size={20} style={{color:BRAND}}/>
          </div>
          <div>
            <p className="font-semibold text-slate-900">Week {week} on protocol</p>
            <p className="text-xs text-slate-400">{peptideArr.length} compound{peptideArr.length!==1?"s":""} active</p>
          </div>
          {streak > 0 && (
            <div className="ml-auto flex items-center gap-1 px-3 py-1.5 rounded-full text-emerald-700 bg-emerald-50 border border-emerald-200 text-sm font-semibold">
              <TrendingUp size={14}/> {streak}
            </div>
          )}
        </div>
      )}

      {peptideArr.length === 0 && (
        <div className="glass-card p-8 text-center">
          <FlaskConical size={40} className="mx-auto mb-3 text-slate-300"/>
          <p className="font-semibold text-slate-700 mb-1">No compounds yet</p>
          <p className="text-sm text-slate-400">Switch to the Peptides tab to add your first compound.</p>
        </div>
      )}
    </div>
  );
}

// ── PeptidesTab ────────────────────────────────────────────────────────────

function PeptidesTab({ peptides, setPeptides, checked, setChecked, vialTracking, setVialTracking, currentDate, setCurrentDate, onSync }) {
  const [editing, setEditing] = useState(null);
  const [showHistory, setShowHistory] = useState(false);

  const dateKey = getDateKey(currentDate);
  const isToday = dateKey === getDateKey(new Date());
  const dayChecked = checked[dateKey] || {};

  const peptideArr = Object.values(peptides);
  const scheduled = peptideArr.filter(p => p.days?.includes(currentDate.getDay()));
  const doneCount = scheduled.filter(p => dayChecked[p.id]).length;

  const toggleDose = (pid) => {
    const newChecked = { ...checked };
    const day = { ...(newChecked[dateKey] || {}) };
    if (day[pid]) {
      delete day[pid];
      const vt = { ...(vialTracking[pid] || {}) };
      vt.dosesUsed = Math.max(0, (vt.dosesUsed || 0) - 1);
      setVialTracking({ ...vialTracking, [pid]: vt });
    } else {
      day[pid] = new Date().toISOString();
      const vt = { ...(vialTracking[pid] || { startDate: new Date().toISOString(), dosesUsed: 0 }) };
      vt.dosesUsed = (vt.dosesUsed || 0) + 1;
      setVialTracking({ ...vialTracking, [pid]: vt });
    }
    newChecked[dateKey] = day;
    setChecked(newChecked);
    onSync?.();
  };

  const savePeptide = (form) => {
    const id = form.id || `p_${Date.now()}_${Math.random().toString(36).slice(2,6)}`;
    setPeptides({ ...peptides, [id]: { ...form, id } });
    if (!vialTracking[id]) setVialTracking(vt => ({ ...vt, [id]: { startDate: new Date().toISOString(), dosesUsed: 0 } }));
    setEditing(null);
  };

  const deletePeptide = (id) => {
    const p = { ...peptides }; delete p[id];
    const vt = { ...vialTracking }; delete vt[id];
    setPeptides(p); setVialTracking(vt); setEditing(null);
  };

  const shiftDate = n => { const d = new Date(currentDate); d.setDate(d.getDate()+n); setCurrentDate(d); };

  // 4-week history for peptides
  const histDays = Array.from({length:28}, (_,i) => { const d = new Date(); d.setDate(d.getDate()-27+i); return d; }).filter(d => getDateKey(d) <= getDateKey(new Date()));
  const weeks = [];
  for (let i=0; i<histDays.length; i+=7) weeks.push(histDays.slice(i,i+7));

  if (showHistory) {
    return (
      <div className="px-4 pb-4 space-y-4">
        <div className="flex items-center gap-3">
          <button onClick={()=>setShowHistory(false)} className="p-2 rounded-full bg-white/60 text-slate-600 glass-card"><ChevronLeft size={18}/></button>
          <h2 className="font-bold text-slate-900">Dose History</h2>
        </div>
        {weeks.reverse().map((week, wi) => (
          <div key={wi} className="glass-card p-4 space-y-2">
            <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide">{wi===0?"This week":wi===1?"Last week":`${(wi)*7}–${(wi+1)*7} days ago`}</p>
            {week.reverse().map(d => {
              const key = getDateKey(d);
              const sched = peptideArr.filter(p=>p.days?.includes(d.getDay()));
              const done = sched.filter(p=>(checked[key]||{})[p.id]).length;
              const isActive = getDateKey(currentDate)===key && !showHistory;
              return (
                <button key={key} onClick={()=>{ setCurrentDate(new Date(d)); setShowHistory(false); }} className="w-full flex items-center gap-3 py-2 px-3 rounded-xl hover:bg-white/50 transition-all text-left">
                  <div className="text-sm font-medium text-slate-700 w-28">{relativeDay(d)}</div>
                  <div className="flex gap-1.5 flex-1">
                    {sched.length===0
                      ? <span className="text-xs text-slate-300">Rest day</span>
                      : sched.map(p=><span key={p.id} className={`w-2.5 h-2.5 rounded-full ${(checked[key]||{})[p.id]?"bg-emerald-400":"bg-slate-200"}`} title={p.name}/>)
                    }
                  </div>
                  {sched.length>0 && <span className="text-xs text-slate-400">{done}/{sched.length}</span>}
                </button>
              );
            })}
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="px-4 pb-4 space-y-4">
      {/* Date nav */}
      <div className="glass-card p-3 flex items-center justify-between">
        <button onClick={()=>shiftDate(-1)} className="p-2 rounded-xl text-slate-500 active:bg-slate-100"><ChevronLeft size={20}/></button>
        <div className="text-center">
          <p className="font-semibold text-slate-900 text-sm">{formatDate(currentDate)}</p>
          {!isToday && <button onClick={()=>setCurrentDate(new Date())} className="text-xs mt-0.5" style={{color:BRAND}}>Back to today</button>}
        </div>
        <button onClick={()=>shiftDate(1)} disabled={isToday} className="p-2 rounded-xl text-slate-500 disabled:opacity-30 active:bg-slate-100"><ChevronRight size={20}/></button>
      </div>

      {/* Progress */}
      {scheduled.length > 0 && (
        <div className="glass-card px-4 py-3">
          <div className="flex justify-between items-center mb-2">
            <span className="text-sm font-semibold text-slate-700">{doneCount} of {scheduled.length} doses</span>
            {doneCount===scheduled.length && <span className="text-xs font-semibold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">Complete ✓</span>}
          </div>
          <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
            <div className="h-full rounded-full transition-all duration-500" style={{width:`${scheduled.length>0?doneCount/scheduled.length*100:0}%`, background:BRAND}}/>
          </div>
        </div>
      )}

      {/* Dose cards */}
      {scheduled.length === 0
        ? <div className="glass-card p-6 text-center text-slate-400 text-sm">Rest day — no doses scheduled</div>
        : scheduled.map(p => {
          const done = !!dayChecked[p.id];
          const vt = vialTracking[p.id] || {};
          const total = dosesPerVial(p);
          const remaining = total - (vt.dosesUsed||0);
          const low = remaining <= 2 && remaining >= 0;
          return (
            <button key={p.id} onClick={()=>toggleDose(p.id)} className={`glass-card w-full p-4 flex items-center gap-3 transition-all active:scale-[0.99] text-left ${done?"border-emerald-300 bg-emerald-50/60":"border-slate-200"}`}
              style={done?{border:"1px solid #6EE7B7",background:"rgba(236,253,245,0.8)"}:{}}>
              <div className={`w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 border-2 transition-all ${done?"border-emerald-400 bg-emerald-400 text-white":"border-slate-300 bg-white"}`}>
                {done && <Check size={14}/>}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className={`w-2 h-2 rounded-full flex-shrink-0 ${CATEGORY_DOT[p.category]||"bg-slate-400"}`}/>
                  <p className="font-semibold text-slate-900 text-sm truncate">{p.name}</p>
                </div>
                <p className="text-xs text-slate-400 mt-0.5">{p.doseLabel} · {calcUnits(p.doseAmount,p)} units</p>
              </div>
              <div className="flex flex-col items-end gap-1">
                {low && remaining >= 0 && <span className="text-xs text-amber-600 font-semibold">{remaining} left</span>}
                <button onClick={e=>{e.stopPropagation();setEditing(p);}} className="text-slate-300 hover:text-slate-500 p-1"><Pencil size={14}/></button>
              </div>
            </button>
          );
        })
      }

      {/* Actions */}
      <div className="flex gap-3">
        <button onClick={()=>setEditing({})} className="flex-1 py-3 rounded-2xl font-semibold text-white text-sm flex items-center justify-center gap-2" style={{background:BRAND}}>
          <Plus size={18}/> Add Compound
        </button>
        <button onClick={()=>setShowHistory(true)} className="px-4 py-3 rounded-2xl glass-card text-slate-600 flex items-center gap-2 text-sm font-medium">
          <Clock size={16}/> History
        </button>
      </div>

      {/* Reset day */}
      {doneCount > 0 && (
        <button onClick={()=>{ if(confirm("Clear all checks for this day?")){ setChecked(c=>({...c,[dateKey]:{}})); }}} className="w-full py-2 text-xs text-slate-400 flex items-center justify-center gap-1">
          <RotateCcw size={12}/> Reset day
        </button>
      )}

      {editing !== null && (
        <PeptideEditor
          peptide={editing}
          vialInfo={editing.id ? vialTracking[editing.id] : null}
          onSave={savePeptide}
          onClose={()=>setEditing(null)}
          onDelete={()=>deletePeptide(editing.id)}
        />
      )}
    </div>
  );
}

// ── NutritionTab ───────────────────────────────────────────────────────────

function NutritionTab({ nutritionData, setNutritionData, favourites, setFavourites, onSync }) {
  const [nutDate, setNutDate] = useState(new Date());
  const [showFoodModal, setShowFoodModal] = useState(false);
  const [editEntry, setEditEntry] = useState(null);
  const [showMicros, setShowMicros] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [expandedHistDay, setExpandedHistDay] = useState(null);

  const dateKey = getDateKey(nutDate);
  const isToday = dateKey === getDateKey(new Date());
  const dayData = nutritionData[dateKey] || { target: 2500, mode: "maintenance", entries: [] };
  const entries = dayData.entries || [];
  const totals = dayTotals(entries);
  const target = dayData.target || 2500;
  const mode = dayData.mode || "maintenance";
  const preset = MACRO_PRESETS[mode] || MACRO_PRESETS.maintenance;
  const macroGoals = { protein: Math.round(target*preset.protein/400), carbs: Math.round(target*preset.carbs/400), fat: Math.round(target*preset.fat/900) };
  const micros = microTotals(entries);

  const updateDay = (updates) => setNutritionData(nd => ({ ...nd, [dateKey]: { ...dayData, ...updates } }));
  const shiftDate = n => { const d = new Date(nutDate); d.setDate(d.getDate()+n); setNutDate(d); };

  const saveEntry = (entry) => {
    const newEntries = editEntry
      ? entries.map(e => e.id===editEntry.id ? entry : e)
      : [...entries, entry];
    updateDay({ entries: newEntries });
    setShowFoodModal(false); setEditEntry(null);
    onSync?.();
  };

  const deleteEntry = (id) => { updateDay({ entries: entries.filter(e=>e.id!==id) }); onSync?.(); };

  const toggleFavourite = (entry) => {
    const already = favourites.find(f=>f.id===entry.id);
    if (already) {
      setFavourites(f=>f.filter(x=>x.id!==entry.id));
    } else {
      const name = entry.note || `${entry.protein}p/${entry.carbs}c/${entry.fat}f`;
      setFavourites(f=>[...f, { ...entry, id: `fav_${Date.now()}`, name }]);
    }
  };

  const histDays = Object.keys(nutritionData)
    .filter(k => k !== dateKey && nutritionData[k]?.entries?.length > 0)
    .sort((a,b)=>b.localeCompare(a))
    .slice(0, 14)
    .map(k => ({ key: k, date: new Date(k+"T12:00:00"), ...nutritionData[k] }));

  return (
    <div className="px-4 pb-4 space-y-4">
      {/* Date nav */}
      <div className="glass-card p-3 flex items-center justify-between">
        <button onClick={()=>shiftDate(-1)} className="p-2 rounded-xl text-slate-500 active:bg-slate-100"><ChevronLeft size={20}/></button>
        <div className="text-center">
          <p className="font-semibold text-slate-900 text-sm">{relativeDay(nutDate)}</p>
          {!isToday && <button onClick={()=>setNutDate(new Date())} className="text-xs mt-0.5" style={{color:BRAND}}>Back to today</button>}
        </div>
        <button onClick={()=>shiftDate(1)} disabled={isToday} className="p-2 rounded-xl text-slate-500 disabled:opacity-30 active:bg-slate-100"><ChevronRight size={20}/></button>
      </div>

      {/* Calorie target + mode */}
      <div className="glass-card p-4 space-y-3">
        <div className="flex items-center justify-between">
          <label className="text-sm font-semibold text-slate-700">Daily Target</label>
          <div className="flex items-center gap-1">
            <input type="number" className="w-20 px-2 py-1 rounded-lg border border-slate-200 bg-white/80 text-slate-900 text-sm text-center focus:outline-none focus:ring-2 focus:ring-[#007AFF]" value={target} onChange={e=>updateDay({target:parseInt(e.target.value)||0})} />
            <span className="text-xs text-slate-400">kcal</span>
          </div>
        </div>
        <div className="flex gap-2">
          {Object.entries(MACRO_PRESETS).map(([k,v])=>(
            <button key={k} onClick={()=>updateDay({mode:k})} className={`flex-1 py-1.5 rounded-xl text-xs font-medium border transition-all ${mode===k?"text-white border-transparent":"bg-white text-slate-500 border-slate-200"}`} style={mode===k?{background:BRAND}:{}}>
              {v.icon} {v.name.split(" ")[0]}
            </button>
          ))}
        </div>
      </div>

      {/* Calorie progress */}
      <div className="glass-card p-4 space-y-3">
        <div className="flex justify-between items-baseline">
          <span className="font-bold text-2xl text-slate-900">{Math.round(totals.calories)}</span>
          <span className="text-sm text-slate-400">/ {target} kcal</span>
        </div>
        <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
          <div className="h-full rounded-full transition-all duration-500" style={{width:`${Math.min(100,(totals.calories/target)*100)}%`, background: totals.calories>target?"#EF4444":BRAND}}/>
        </div>
        <div className="grid grid-cols-3 gap-2 text-center text-xs">
          {[["Protein","protein","#007AFF"],["Carbs","carbs","#F59E0B"],["Fat","fat","#8B5CF6"]].map(([label,k,color])=>(
            <div key={k}>
              <p className="font-bold text-slate-900">{Math.round(totals[k])}g</p>
              <p style={{color}} className="font-medium">{label}</p>
              <div className="h-1.5 bg-slate-100 rounded-full mt-1 overflow-hidden">
                <div className="h-full rounded-full" style={{width:`${Math.min(100,(totals[k]/Math.max(1,macroGoals[k]))*100)}%`,background:color}}/>
              </div>
              <p className="text-slate-300 mt-0.5">/{macroGoals[k]}g</p>
            </div>
          ))}
        </div>
      </div>

      {/* Micros toggle */}
      {Object.values(micros).some(v=>v>0) && (
        <button className="glass-card w-full p-3 flex items-center justify-between text-sm font-medium text-slate-700" onClick={()=>setShowMicros(s=>!s)}>
          <span>Micronutrients</span>
          {showMicros ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
        </button>
      )}
      {showMicros && Object.values(micros).some(v=>v>0) && (
        <div className="glass-card p-4 space-y-2">
          {Object.entries(RDA).map(([k,rda])=>{
            const val = micros[k]||0;
            if(!val) return null;
            const pct = Math.min(100,Math.round(val/rda*100));
            return (
              <div key={k}>
                <div className="flex justify-between text-xs text-slate-600 mb-1">
                  <span>{MICRO_LABELS[k].split(" (")[0]}</span>
                  <span>{Math.round(val)} / {rda} ({pct}%)</span>
                </div>
                <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                  <div className="h-full rounded-full transition-all" style={{width:`${pct}%`,background:pct>=100?"#34D399":BRAND}}/>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Food entries */}
      <div className="space-y-2">
        {entries.map(e => {
          const isFav = favourites.some(f=>f.note===e.note&&f.protein===e.protein&&f.carbs===e.carbs&&f.fat===e.fat);
          return (
            <div key={e.id} className="glass-card p-3 flex items-center gap-3">
              <div className="flex-1 min-w-0">
                <p className="font-medium text-slate-800 text-sm truncate">{e.note||"Entry"}</p>
                <p className="text-xs text-slate-400">{e.protein}p · {e.carbs}c · {e.fat}f · {entryCalories(e)} kcal</p>
              </div>
              <div className="flex gap-1 items-center flex-shrink-0">
                <button onClick={()=>toggleFavourite(e)} className="p-1.5 rounded-lg text-amber-400 hover:bg-amber-50">
                  <Star size={15} fill={isFav?"#F59E0B":"none"}/>
                </button>
                <button onClick={()=>{setEditEntry(e);setShowFoodModal(true);}} className="p-1.5 rounded-lg text-slate-400 hover:bg-slate-100">
                  <Pencil size={15}/>
                </button>
                <button onClick={()=>deleteEntry(e.id)} className="p-1.5 rounded-lg text-red-400 hover:bg-red-50">
                  <Trash2 size={15}/>
                </button>
              </div>
            </div>
          );
        })}
      </div>

      <button onClick={()=>{setEditEntry(null);setShowFoodModal(true);}} className="w-full py-3 rounded-2xl font-semibold text-white text-sm flex items-center justify-center gap-2" style={{background:BRAND}}>
        <Plus size={18}/> Log Food
      </button>

      {/* Nutrition history */}
      {histDays.length > 0 && (
        <div>
          <button className="w-full glass-card p-3 flex items-center justify-between text-sm font-medium text-slate-700" onClick={()=>setShowHistory(s=>!s)}>
            <span className="flex items-center gap-2"><Clock size={16}/>Past Entries</span>
            {showHistory ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
          </button>
          {showHistory && (
            <div className="mt-2 space-y-2">
              {histDays.map(hd => {
                const ht = dayTotals(hd.entries||[]);
                const expanded = expandedHistDay===hd.key;
                return (
                  <div key={hd.key} className="glass-card overflow-hidden">
                    <button className="w-full p-3 flex items-center gap-3 text-left" onClick={()=>setExpandedHistDay(expanded?null:hd.key)}>
                      <div className="flex-1">
                        <p className="font-medium text-slate-800 text-sm">{relativeDay(hd.date)}</p>
                        <p className="text-xs text-slate-400">{Math.round(ht.calories)} kcal · {Math.round(ht.protein)}p {Math.round(ht.carbs)}c {Math.round(ht.fat)}f</p>
                      </div>
                      <div className="w-20 h-2 bg-slate-100 rounded-full overflow-hidden">
                        <div className="h-full rounded-full" style={{width:`${Math.min(100,(ht.calories/(hd.target||2500))*100)}%`,background:ht.calories>(hd.target||2500)?"#EF4444":"#34D399"}}/>
                      </div>
                      {expanded ? <ChevronUp size={14} className="text-slate-400"/> : <ChevronDown size={14} className="text-slate-400"/>}
                    </button>
                    {expanded && (
                      <div className="border-t border-slate-100 px-3 pb-3 pt-2 space-y-1.5">
                        {(hd.entries||[]).map(e=>(
                          <div key={e.id} className="flex items-center gap-2 py-1">
                            <div className="flex-1">
                              <p className="text-sm text-slate-700">{e.note||"Entry"}</p>
                              <p className="text-xs text-slate-400">{e.protein}p · {e.carbs}c · {e.fat}f · {entryCalories(e)} kcal</p>
                            </div>
                            <div className="flex gap-1">
                              <button onClick={()=>{ setNutDate(hd.date); setEditEntry(e); setShowFoodModal(true); setShowHistory(false); }} className="p-1 text-slate-400"><Pencil size={13}/></button>
                              <button onClick={()=>setNutritionData(nd=>({ ...nd, [hd.key]:{ ...nd[hd.key], entries:(nd[hd.key]?.entries||[]).filter(x=>x.id!==e.id) } }))} className="p-1 text-red-400"><Trash2 size={13}/></button>
                            </div>
                          </div>
                        ))}
                        <button onClick={()=>{ setNutDate(hd.date); setEditEntry(null); setShowFoodModal(true); setShowHistory(false); }} className="text-xs mt-1 flex items-center gap-1" style={{color:BRAND}}>
                          <Plus size={12}/> Add entry to this day
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {showFoodModal && (
        <FoodModal
          initial={editEntry}
          favourites={favourites}
          onFavourite={toggleFavourite}
          onSave={saveEntry}
          onClose={()=>{setShowFoodModal(false);setEditEntry(null);}}
        />
      )}
    </div>
  );
}

// ── SettingsTab ────────────────────────────────────────────────────────────

// ── Hermes Sync utilities ──────────────────────────────────────────────────

const HS = {
  get enabled() { return localStorage.getItem('rico.hermesSync.enabled') === 'true'; },
  get url()     { return localStorage.getItem('rico.hermesSync.url') || ''; },
  get token()   { return localStorage.getItem('rico.hermesSync.token') || ''; },
  get lastAt()  { return localStorage.getItem('rico.hermesSync.lastSyncAt') || ''; },
  get status()  { return localStorage.getItem('rico.hermesSync.lastSyncStatus') || 'never'; },
  set(key, val) { localStorage.setItem('rico.hermesSync.' + key, val); },
};

function buildSyncPayload(peptides, checked, nutritionData, stackStartDate) {
  const today = getDateKey(new Date());
  const dayOfWeek = new Date().getDay();
  const dayChecked = checked[today] || {};
  const entries = nutritionData[today]?.entries || [];
  const target = nutritionData[today]?.target || 0;
  const totals = dayTotals(entries);

  const peptidePayload = {};
  Object.values(peptides).forEach(p => {
    if (!p.days?.includes(dayOfWeek)) return;
    const takenAt = dayChecked[p.id];
    const times = takenAt ? [new Date(takenAt).toTimeString().slice(0, 5)] : [];
    peptidePayload[p.name] = { scheduled: 1, taken: takenAt ? 1 : 0, times };
  });

  const week = stackStartDate
    ? Math.ceil((Date.now() - new Date(stackStartDate).getTime()) / (7 * 86400000))
    : 0;

  return {
    date: today,
    peptides: peptidePayload,
    nutrition: {
      calories: Math.round(totals.calories),
      target,
      protein_g: Math.round(totals.protein),
      carbs_g: Math.round(totals.carbs),
      fat_g: Math.round(totals.fat),
    },
    week_on_protocol: week,
    client_version: '2.0',
  };
}

async function doHermesSync(payload, url, token) {
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    const data = await res.json().catch(() => ({}));
    return res.ok && data.ok === true ? 'success' : 'failed';
  } catch {
    return 'failed';
  }
}

// ── SettingsTab ────────────────────────────────────────────────────────────

function SettingsTab({ stackStartDate, setStackStartDate, onReset, favourites, setFavourites, peptides, checked, nutritionData }) {
  const [confirmReset, setConfirmReset] = useState(false);
  const [syncEnabled, setSyncEnabled] = useState(() => HS.enabled);
  const [syncUrl, setSyncUrl]         = useState(() => HS.url);
  const [syncToken, setSyncToken]     = useState(() => HS.token);
  const [lastSyncAt, setLastSyncAt]   = useState(() => HS.lastAt);
  const [syncStatus, setSyncStatus]   = useState(() => HS.status);
  const [testLoading, setTestLoading] = useState(false);
  const [toast, setToast]             = useState(null);

  const showToast = (type) => { setToast(type); setTimeout(() => setToast(null), 3000); };

  const handleToggle = (val) => { setSyncEnabled(val); HS.set('enabled', val); };
  const handleUrl    = (val) => { setSyncUrl(val);     HS.set('url', val); };
  const handleToken  = (val) => { setSyncToken(val);   HS.set('token', val); };

  const testSync = async () => {
    if (!syncUrl || !syncToken) return;
    setTestLoading(true);
    const payload = buildSyncPayload(peptides, checked, nutritionData, stackStartDate);
    const result = await doHermesSync(payload, syncUrl, syncToken);
    HS.set('lastSyncAt', new Date().toISOString());
    HS.set('lastSyncStatus', result);
    setLastSyncAt(HS.lastAt);
    setSyncStatus(result);
    setTestLoading(false);
    showToast(result);
  };

  const fmtDate = iso => iso ? new Date(iso).toLocaleString() : 'Never';

  return (
    <div className="px-4 pb-4 space-y-4">
      <div className="glass-card p-4 space-y-3">
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Stack</p>
        <div className="flex items-center justify-between">
          <span className="text-sm font-medium text-slate-700">Protocol start date</span>
          <input type="date" className="px-3 py-1.5 rounded-xl border border-slate-200 bg-white/80 text-slate-800 text-sm focus:outline-none focus:ring-2 focus:ring-[#007AFF]"
            value={stackStartDate ? stackStartDate.split("T")[0] : ""}
            onChange={e=>setStackStartDate(e.target.value ? new Date(e.target.value).toISOString() : null)}
          />
        </div>
      </div>

      {favourites.length > 0 && (
        <div className="glass-card p-4 space-y-3">
          <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Favourite Meals</p>
          {favourites.map(fav=>(
            <div key={fav.id} className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-slate-800">{fav.name}</p>
                <p className="text-xs text-slate-400">{fav.protein}p · {fav.carbs}c · {fav.fat}f</p>
              </div>
              <button onClick={()=>setFavourites(f=>f.filter(x=>x.id!==fav.id))} className="p-1.5 rounded-lg text-red-400 hover:bg-red-50"><Trash2 size={15}/></button>
            </div>
          ))}
        </div>
      )}

      <div className="glass-card p-4 space-y-3">
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Data</p>
        {!confirmReset
          ? <button onClick={()=>setConfirmReset(true)} className="w-full py-3 rounded-xl text-red-500 bg-red-50 border border-red-200 font-medium text-sm">Reset All Data</button>
          : <div className="space-y-2">
              <p className="text-sm text-red-600 font-medium">This will erase everything. Are you sure?</p>
              <div className="flex gap-3">
                <button onClick={()=>setConfirmReset(false)} className="flex-1 py-2.5 rounded-xl border border-slate-200 text-slate-600 text-sm font-medium">Cancel</button>
                <button onClick={onReset} className="flex-1 py-2.5 rounded-xl bg-red-500 text-white text-sm font-medium">Erase Everything</button>
              </div>
            </div>
        }
      </div>

      {/* Hermes Sync */}
      <div className="glass-card p-4 space-y-4">
        <p className="text-xs font-semibold text-slate-400 uppercase tracking-wide">Hermes Sync</p>

        <div className="flex items-center justify-between">
          <span className="text-sm font-medium text-slate-700">Enable cloud sync</span>
          <button
            onClick={()=>handleToggle(!syncEnabled)}
            className={`relative w-12 h-6 rounded-full transition-colors ${syncEnabled ? 'bg-[#007AFF]' : 'bg-slate-200'}`}
          >
            <span className={`absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform ${syncEnabled ? 'translate-x-6' : 'translate-x-0'}`}/>
          </button>
        </div>

        <div className="space-y-2">
          <div>
            <label className="text-xs text-slate-400 mb-1 block">Sync URL</label>
            <input
              type="url"
              className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-800 text-sm focus:outline-none focus:ring-2 focus:ring-[#007AFF]"
              placeholder="https://your-endpoint.com/sync"
              value={syncUrl}
              onChange={e=>handleUrl(e.target.value)}
              autoComplete="off"
            />
          </div>
          <div>
            <label className="text-xs text-slate-400 mb-1 block">Auth token</label>
            <input
              type="password"
              className="w-full px-3 py-2 rounded-xl border border-slate-200 bg-white/80 text-slate-800 text-sm focus:outline-none focus:ring-2 focus:ring-[#007AFF]"
              placeholder="••••••••"
              value={syncToken}
              onChange={e=>handleToken(e.target.value)}
              autoComplete="new-password"
            />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-3 text-xs text-slate-500">
          <div>
            <p className="font-medium text-slate-400">Last sync</p>
            <p className="text-slate-700 mt-0.5">{fmtDate(lastSyncAt)}</p>
          </div>
          <div>
            <p className="font-medium text-slate-400">Status</p>
            <p className={`mt-0.5 font-semibold ${syncStatus==='success'?'text-emerald-600':syncStatus==='failed'?'text-red-500':'text-slate-400'}`}>
              {syncStatus==='success'?'✓ Success':syncStatus==='failed'?'✗ Failed':'— Never'}
            </p>
          </div>
        </div>

        <button
          onClick={testSync}
          disabled={!syncUrl || !syncToken || testLoading}
          className="w-full py-2.5 rounded-xl text-sm font-semibold text-white disabled:opacity-40 transition-opacity"
          style={{background:BRAND}}
        >
          {testLoading ? 'Syncing…' : 'Test Sync Now'}
        </button>

        <p className="text-xs text-slate-400 leading-relaxed border-t border-slate-100 pt-3">
          When enabled, RICO sends a daily snapshot of your peptide adherence and nutrition totals to YOUR endpoint only. Data never leaves your device unless this toggle is ON. You can disable anytime.
        </p>
      </div>

      {toast && (
        <div className={`fixed top-20 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-2xl text-sm font-semibold text-white shadow-lg transition-all ${toast==='success'?'bg-emerald-500':'bg-red-500'}`}>
          {toast==='success' ? '✓ Sync successful' : '✗ Sync failed'}
        </div>
      )}

      <p className="text-center text-xs text-slate-300 pb-2">RICO v2.0 · All data stored locally</p>
    </div>
  );
}

// ── BottomNav ──────────────────────────────────────────────────────────────

function BottomNav({ tab, setTab }) {
  const items = [
    { id:"dashboard", icon:LayoutDashboard, label:"Dashboard" },
    { id:"peptides",  icon:Beaker,          label:"Peptides"  },
    { id:"nutrition", icon:Apple,           label:"Nutrition" },
    { id:"settings",  icon:Settings,        label:"Settings"  },
  ];
  return (
    <div className="glass-nav fixed bottom-0 left-0 right-0 flex justify-around items-center px-2 pb-safe" style={{height:"64px"}}>
      {items.map(({id,icon:Icon,label})=>{
        const active = tab===id;
        return (
          <button key={id} onClick={()=>setTab(id)} className="flex flex-col items-center gap-0.5 py-2 px-4 rounded-2xl transition-all" style={active?{color:BRAND}:{color:"#94A3B8"}}>
            <Icon size={22} strokeWidth={active?2.5:1.8}/>
            <span className={`text-[10px] font-semibold tracking-wide ${active?"":"opacity-70"}`}>{label}</span>
          </button>
        );
      })}
    </div>
  );
}

// ── App ────────────────────────────────────────────────────────────────────

export default function App() {
  const [tab, setTab] = useState("dashboard");
  const [currentDate, setCurrentDate] = useState(new Date());
  const [peptides, setPeptides] = useState({});
  const [checked, setChecked] = useState({});
  const [vialTracking, setVialTracking] = useState({});
  const [stackStartDate, setStackStartDate] = useState(null);
  const [nutritionData, setNutritionData] = useState({});
  const [favourites, setFavourites] = useState([]);
  const [showAssistant, setShowAssistant] = useState(false);
  const lastSyncRef = useRef(0);

  // Load from localStorage
  useEffect(() => {
    try {
      const raw = localStorage.getItem("rico-stack-v2") || localStorage.getItem("rico-stack-v1");
      if (raw) {
        const d = JSON.parse(raw);
        if (d.peptides)      setPeptides(d.peptides);
        if (d.checked)       setChecked(d.checked);
        if (d.vialTracking)  setVialTracking(d.vialTracking);
        if (d.stackStartDate)setStackStartDate(d.stackStartDate);
        if (d.nutritionData) setNutritionData(d.nutritionData);
        if (d.favourites)    setFavourites(d.favourites);
      }
    } catch {}
  }, []);

  // Auto-save
  useEffect(() => {
    try {
      localStorage.setItem("rico-stack-v2", JSON.stringify({ peptides, checked, vialTracking, stackStartDate, nutritionData, favourites }));
    } catch {}
  }, [peptides, checked, vialTracking, stackStartDate, nutritionData, favourites]);

  // Streak
  const streak = (() => {
    const peptideArr = Object.values(peptides);
    if (peptideArr.length === 0) return 0;
    let s = 0, d = new Date();
    while (true) {
      const key = getDateKey(d);
      const sched = peptideArr.filter(p=>p.days?.includes(d.getDay()));
      if (sched.length > 0) {
        const dayC = checked[key]||{};
        if (!sched.every(p=>dayC[p.id])) break;
        s++;
      }
      d.setDate(d.getDate()-1);
      if (s > 365) break;
    }
    return s;
  })();

  const triggerSync = useCallback(async () => {
    if (!HS.enabled) return;
    const url = HS.url; const token = HS.token;
    if (!url || !token) return;
    const now = Date.now();
    if (now - lastSyncRef.current < 5 * 60 * 1000) return;
    lastSyncRef.current = now;
    const payload = buildSyncPayload(peptides, checked, nutritionData, stackStartDate);
    const status = await doHermesSync(payload, url, token);
    HS.set('lastSyncAt', new Date().toISOString());
    HS.set('lastSyncStatus', status);
  }, [peptides, checked, nutritionData, stackStartDate]);

  // Sync on app open
  useEffect(() => { triggerSync(); }, []);

  const resetAll = () => {
    setPeptides({}); setChecked({}); setVialTracking({}); setStackStartDate(null); setNutritionData({}); setFavourites([]);
    localStorage.removeItem("rico-stack-v2");
    localStorage.removeItem("rico-stack-v1");
  };

  const assistantContext = {
    peptides,
    streak,
    nutritionToday: nutritionData[getDateKey(new Date())],
  };

  return (
    <div className="min-h-screen bg-[#F2F2F7]">
      {/* Header */}
      <div className="glass-header fixed top-0 left-0 right-0 z-40 px-4 py-3 flex items-center gap-3">
        <img src={LOGO_SRC} alt="RICO" className="w-8 h-8 rounded-xl object-cover"/>
        <span className="text-lg font-extrabold text-slate-900 tracking-tight">RICO</span>
        {streak > 0 && (
          <span className="flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-bold text-emerald-700 bg-emerald-50 border border-emerald-200 ml-1">
            <TrendingUp size={12}/> {streak}
          </span>
        )}
      </div>

      {/* Content */}
      <div className="pt-16 pb-20 overflow-y-auto min-h-screen">
        <div className="pt-4">
          {tab === "dashboard" && (
            <DashboardTab peptides={peptides} checked={checked} nutritionData={nutritionData} stackStartDate={stackStartDate} streak={streak}/>
          )}
          {tab === "peptides" && (
            <PeptidesTab peptides={peptides} setPeptides={setPeptides} checked={checked} setChecked={setChecked}
              vialTracking={vialTracking} setVialTracking={setVialTracking} currentDate={currentDate} setCurrentDate={setCurrentDate} onSync={triggerSync}/>
          )}
          {tab === "nutrition" && (
            <NutritionTab nutritionData={nutritionData} setNutritionData={setNutritionData} favourites={favourites} setFavourites={setFavourites} onSync={triggerSync}/>
          )}
          {tab === "settings" && (
            <SettingsTab stackStartDate={stackStartDate} setStackStartDate={setStackStartDate} onReset={resetAll} favourites={favourites} setFavourites={setFavourites} peptides={peptides} checked={checked} nutritionData={nutritionData}/>
          )}
        </div>
      </div>

      <BottomNav tab={tab} setTab={setTab}/>

      {/* Claude assistant FAB */}
      <button
        onClick={()=>setShowAssistant(true)}
        className="fixed right-4 z-40 w-12 h-12 rounded-full shadow-lg flex items-center justify-center text-white transition-transform active:scale-95"
        style={{bottom:"80px", background:BRAND}}
      >
        <MessageCircle size={22}/>
      </button>

      {showAssistant && <AssistantModal onClose={()=>setShowAssistant(false)} context={assistantContext}/>}
    </div>
  );
}
